#include <bits/stdc++.h>
using namespace std;
int n,a[100005],ans;
bool mark[100005];
vector<int> g[100005];
bool dfs(int x){
    bool flag=bool(a[x]);
    mark[x]=true;
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(!mark[g[x][i]])
            if(dfs(g[x][i]))
                flag=true,ans+=(a[x]==0),a[x]=1;
    return flag;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        if(a[i]){
            dfs(i);
            break;
        }
    cout<<ans;
    return 0;
}
